inseridos = 0
atualizados = 0
with engine.connect() as conn:
    for (eid, ano, mes, valor) in dados:
        r = conn.execute(text("SELECT id FROM historico_faturamento WHERE empresa_id=:e AND ano=:a AND mes=:m"), {"e":eid,"a":ano,"m":mes}).fetchone()
        if r:
            conn.execute(text("UPDATE historico_faturamento SET valor=:v WHERE empresa_id=:e AND ano=:a AND mes=:m"), {"v":valor,"e":eid,"a":ano,"m":mes})
            atualizados += 1
        else:
            conn.execute(text("INSERT INTO historico_faturamento (empresa_id,ano,mes,valor) VALUES (:e,:a,:m,:v)"), {"e":eid,"a":ano,"m":mes,"v":valor})
            inseridos += 1
    conn.commit()

print(f"OK — {atualizados} atualizados, {inseridos} inseridos, total {len(dados)} registros")
